#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n;
    scanf("%d", &n);
    int *start = (int*)malloc(n * sizeof(int));
    int *end = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &start[i], &end[i]);
    }
    qsort(start, n, sizeof(int), compare);
    qsort(end, n, sizeof(int), compare);
    int i = 0, j = 0, rooms = 0, max_rooms = 0;
    while (i < n && j < n) {
        if (start[i] < end[j]) {
            rooms++;
            i++;
        } else {
            rooms--;
            j++;
        }
        max_rooms = (max_rooms > rooms) ? max_rooms : rooms;
    }
    printf("%d\n", max_rooms);
    free(start);
    free(end);
    return 0;
}

