#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<pair<int, int>> lectures(n);
    for (int i = 0; i < n; i++) {
        cin >> lectures[i].first >> lectures[i].second;
    }
    sort(lectures.begin(), lectures.end());
    priority_queue<int, vector<int>, greater<int>> end_times;
    int max_rooms = 0;
    for (int i = 0; i < n; i++) {
        if (!end_times.empty() && end_times.top() <= lectures[i].first) {
            end_times.pop();
        }
        end_times.push(lectures[i].second);
        max_rooms = max(max_rooms, (int)end_times.size());
    }
    cout << max_rooms << endl;
    return 0;
}

