import java.util.PriorityQueue;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[][] lectures = new int[n][2];
        for (int i = 0; i < n; i++) {
            lectures[i][0] = scanner.nextInt();
            lectures[i][1] = scanner.nextInt();
        }
        Arrays.sort(lectures, (a, b) -> a[0] - b[0]);
        PriorityQueue<Integer> end_times = new PriorityQueue<>();
        int max_rooms = 0;
        for (int i = 0; i < n; i++) {
            if (!end_times.isEmpty() && end_times.peek() <= lectures[i][0]) {
                end_times.poll();
            }
            end_times.offer(lectures[i][1]);
            max_rooms = Math.max(max_rooms, end_times.size());
        }
        System.out.println(max_rooms);
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let lectures = [];
let i = 0;
rl.on('line', (line) => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        lectures.push(line.split(' ').map((x) => parseInt(x)));
    }
    i++;
    if (i > n) {
        lectures.sort((a, b) => a[0] - b[0]);
        let end_times = [];
        let max_rooms = 0;
        for (let j = 0; j < n; j++) {
            if (end_times.length > 0 && end_times[0] <= lectures[j][0]) {
                end_times.shift();
            }
            end_times.push(lectures[j][1]);
            end_times.sort((a, b) => a - b);
            max_rooms = Math.max(max_rooms, end_times.length);
        }
        console.log(max_rooms);
        rl.close();
    }
});
